 ```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Personal Expense Tracker</title>
  <style>
    body {
      font-family: Arial, sans-serif;
      margin: 20px;
      background: #f5f5f5;
      color: #333;
    }
    .container {
      max-width: 800px;
      margin: 0 auto;
      background: #fff;
      padding: 20px;
      border-radius: 8px;
    }
    h1, h2, h3 {
      margin-top: 0;
    }
    form, .filters {
      margin-bottom: 20px;
    }
    label {
      display: block;
      margin: 8px 0 4px;
      font-weight: bold;
    }
    input, select, button {
      padding: 8px;
      font-size: 1rem;
    }
    .form-row {
      display: flex;
      gap: 10px;
      flex-wrap: wrap;
      align-items: flex-end;
    }
    .form-group {
      display: flex;
      flex-direction: column;
    }
    #form-error {
      color: #c00;
      min-height: 1.2em;
      margin-top: 6px;
    }
    table {
      width: 100%;
      border-collapse: collapse;
      margin-top: 10px;
    }
    th, td {
      text-align: left;
      padding: 8px;
      border-bottom: 1px solid #ddd;
    }
    .exp-del {
      background: #c00;
      color: #fff;
      border: none;
      border-radius: 4px;
      cursor: pointer;
    }
    .summary {
      margin-top: 20px;
    }
    .cat-totals {
      display: flex;
      flex-wrap: wrap;
      gap: 10px;
      margin-top: 10px;
    }
    .cat-total {
      background: #eee;
      padding: 8px 12px;
      border-radius: 4px;
    }
  </style>
</head>
<body>
  <div class="container">
    <h1>Personal Expense Tracker</h1>

    <form id="expense-form">
      <div class="form-row">
        <div class="form-group">
          <label for="amount">Amount</label>
          <input type="number" id="amount" step="0.01">
        </div>
        <div class="form-group">
          <label for="category">Category</label>
          <select id="category">
            <option value="groceries">Groceries</option>
            <option value="transport">Transport</option>
            <option value="bills">Bills</option>
            <option value="fun">Fun</option>
          </select>
        </div>
        <div class="form-group">
          <label for="date">Date</label>
          <input type="date" id="date">
        </div>
        <div class="form-group">
          <label for="note">Note (optional)</label>
          <input type="text" id="note">
        </div>
        <button type="submit" id="add-expense">Add Expense</button>
      </div>
      <div id="form-error"></div>
    </form>

    <div class="filters">
      <h2>Filters</h2>
      <div class="form-row">
        <div class="form-group">
          <label for="filter-category">Category</label>
          <select id="filter-category">
            <option value="all">All</option>
            <option value="groceries">Groceries</option>
            <option value="transport">Transport</option>
            <option value="bills">Bills</option>
            <option value="fun">Fun</option>
          </select>
        </div>
        <div class="form-group">
          <label for="filter-from">From</label>
          <input type="date" id="filter-from">
        </div>
        <div class="form-group">
          <label for="filter-to">To</label>
          <input type="date" id="filter-to">
        </div>
      </div>
    </div>

    <h2>Expenses</h2>
    <table>
      <thead>
        <tr>
          <th>Amount</th>
          <th>Category</th>
          <th>Date</th>
          <th></th>
        </tr>
      </thead>
      <tbody id="expense-list"></tbody>
    </table>

    <div class="summary">
      <h2>Total: <span id="total">0.00</span></h2>
      <h3>By Category</h3>
      <div id="category-summary" class="cat-totals"></div>
    </div>
  </div>

  <script>
    const STORAGE_KEY = 'expense_tracker_data';
    const categories = ['groceries', 'transport', 'bills', 'fun'];

    const amountInput = document.getElementById('amount');
    const categoryInput = document.getElementById('category');
    const dateInput = document.getElementById('date');
    const noteInput = document.getElementById('note');
    const formError = document.getElementById('form-error');
    const expenseForm = document.getElementById('expense-form');
    const expenseList = document.getElementById('expense-list');
    const totalEl = document.getElementById('total');
    const categorySummary = document.getElementById('category-summary');
    const filterCategory = document.getElementById('filter-category');
    const filterFrom = document.getElementById('filter-from');
    const filterTo = document.getElementById('filter-to');

    let expenses = [];

    function loadExpenses() {
      try {
        const data = localStorage.getItem(STORAGE_KEY);
        expenses = data ? JSON.parse(data) : [];
      } catch (e) {
        expenses = [];
      }
      if (!Array.isArray(expenses)) {
        expenses = [];
      }
    }

    function saveExpenses() {
      try {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
      } catch (e) {
        // Storage unavailable; continue in memory
      }
    }

    function formatMoney(num) {
      return num.toFixed(2);
    }

    function isVisible(expense) {
      const cat = filterCategory.value;
      if (cat !== 'all' && expense.category !== cat) {
        return false;
      }
      const from = filterFrom.value;
      const to = filterTo.value;
      if (from && expense.date < from) {
        return false;
      }
      if (to && expense.date > to) {
        return false;
      }
      return true;
    }

    function render() {
      const sorted = expenses.slice().sort((a, b) => {
        if (a.date !== b.date) {
          return a.date < b.date ? 1 : -1;
        }
        return (b.id || 0) - (a.id || 0);
      });

      expenseList.innerHTML = '';
      let total = 0;
      const catTotals = {};
      categories.forEach(c => catTotals[c] = 0);

      sorted.forEach(expense => {
        const visible = isVisible(expense);
        const row = document.createElement('tr');
        row.className = 'expense';
        if (!visible) {
          row.style.display = 'none';
        }
        row.innerHTML = `
          <td>${formatMoney(expense.amount)}</td>
          <td>${expense.category}</td>
          <td>${expense.date}</td>
          <td><button class="exp-del" data-id="${expense.id}">Delete</button></td>
        `;
        expenseList.appendChild(row);

        if (visible) {
          total += expense.amount;
          if (catTotals.hasOwnProperty(expense.category)) {
            catTotals[expense.category] += expense.amount;
          }
        }
      });

      totalEl.textContent = formatMoney(total);

      categorySummary.innerHTML = '';
      categories.forEach(c => {
        const div = document.createElement('div');
        div.className = 'cat-total';
        div.setAttribute('data-cat', c);
        div.textContent = `${c}: $${formatMoney(catTotals[c])}`;
        categorySummary.appendChild(div);
      });

      document.querySelectorAll('.exp-del').forEach(btn => {
        btn.addEventListener('click', handleDelete);
      });
    }

    function handleDelete(e) {
      const id = Number(e.target.getAttribute('data-id'));
      expenses = expenses.filter(ex => ex.id !== id);
      saveExpenses();
      render();
    }

    expenseForm.addEventListener('submit', function(e) {
      e.preventDefault();
      const amountVal = amountInput.value;
      const amount = parseFloat(amountVal);

      if (amountVal.trim() === '' || isNaN(amount) || amount <= 0) {
        formError.textContent = 'Please enter a positive numeric amount.';
        return;
      }
      if (!dateInput.value) {
        formError.textContent = 'Please select a date.';
        return;
      }

      formError.textContent = '';

      const expense = {
        id: Date.now(),
        amount: amount,
        category: categoryInput.value,
        date: dateInput.value,
        note: noteInput.value.trim()
      };

      expenses.push(expense);
      saveExpenses();
      render();

      amountInput.value = '';
    });

    filterCategory.addEventListener('change', render);
    filterFrom.addEventListener('change', render);
    filterTo.addEventListener('change', render);

    loadExpenses();
    render();
  </script>
</body>
</html>
